				"not":      1,
				"that":     1,
				"is":       1,
				"the":      1,
				"question": 1,
			},
		},
		{
			name:  "leading and trailing whitespace",
			input: "  spaces everywhere  ",
			want:  map[string]int{"spaces": 1, "everywhere": 1},
